// Filtra apenas registros do dia de hoje
const hoje = new Date().toLocaleDateString('pt-BR', { timeZone: 'America/Sao_Paulo' });
const itens = $input.all().map(i => i.json);

// Filtra registros do dia (Data/Hora começa com a data de hoje)
const doDia = itens.filter(i => {
  const dt = (i['Data/Hora'] || '').split(',')[0].trim();
  return dt === hoje;
});

if (doDia.length === 0) {
  return [{ json: {
    totalItens: 0,
    resumo: `📊 *Relatório PiTa® — ${hoje}*\n\nNenhuma precificação registrada hoje.`,
    vazio: true
  }}];
}

// Calcula totais
const margens = doDia.map(i => parseFloat(i['Margem Líq. (%)'] || 0));
const margemMedia = (margens.reduce((a, b) => a + b, 0) / margens.length);
const produtos = [...new Set(doDia.map(i => i['Produto']))];

const saudaveis = doDia.filter(i => parseFloat(i['Margem Líq. (%)'] || 0) >= 25).length;
const alerta    = doDia.filter(i => { const m = parseFloat(i['Margem Líq. (%)'] || 0); return m >= 11 && m < 25; }).length;
const perigo    = doDia.filter(i => parseFloat(i['Margem Líq. (%)'] || 0) < 11).length;

const listaProdutos = produtos.map(p => {
  const item = doDia.find(i => i['Produto'] === p);
  const saude = item['Saúde'] || '';
  return `  • ${p} — R$ ${item['Preço Final (R$)']} ${saude}`;
}).join('\n');

const resumo = `📊 *Relatório PiTa® — ${hoje}*

*Total de precificações:* ${doDia.length}
*Margem média do dia:* ${margemMedia.toFixed(1)}%

*Saúde das margens:*
  ✅ Saudáveis (≥25%): ${saudaveis}
  ⚠️ Alerta (11-24%): ${alerta}
  🚨 Perigosas (<10%): ${perigo}

*Produtos calculados hoje:*
${listaProdutos}

_Relatório gerado automaticamente por n8n · PiTa® 2026_`;

return [{ json: { totalItens: doDia.length, margemMedia: margemMedia.toFixed(1), resumo, vazio: false } }];
